BEGIN
  if coalesce(NEW.withdraw_status::text, '') = '' or NEW.withdraw_status <> '1' then NEW.withdraw_status := '0';end if;
  if coalesce(NEW.fin_status::text, '') = '' or NEW.fin_status <> '1' then NEW.fin_status := '0';end if;

  if coalesce(OLD.WITHDRAW_DOC_NO::text, '') = '' and (NEW.WITHDRAW_DOC_NO IS NOT NULL AND NEW.WITHDRAW_DOC_NO::text <> '') then
    if pka.auto_entry then
      NEW.entry_id := current_setting('app.login_id', true);
      NEW.entry_date := statement_timestamp();
      NEW.branch_id := current_setting('app.login_br', true);
    end if;
  end if;

  --Niorn 2023-05-29 TGE คำขอถอนหุ้นบางส่วน ให้คีย์คำขอไว้ล่วงหน้าก่อน trans type เป็น REQ
  if coalesce(NEW.approve_status::text, '') = ''  then NEW.approve_status := '2';end if;


RETURN NEW;
end
